<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';exigirRol(['usuario']);$pdo=obtenerConexion();$pagina=max(1,(int)($_GET['pagina']??1));$limite=10;$q=$pdo->prepare('SELECT COUNT(*) FROM pedidos WHERE usuario_id=:u');$q->execute(['u'=>$_SESSION['usuario_id']]);$total=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT p.*,d.codigo_generacion,d.numero_control,d.estado estado_dte FROM pedidos p LEFT JOIN dte_documentos d ON d.pedido_id=p.id WHERE p.usuario_id=:u ORDER BY p.created_at DESC LIMIT :lim OFFSET :off');$q->bindValue(':u',(int)$_SESSION['usuario_id'],PDO::PARAM_INT);$q->bindValue(':lim',$limite,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$limite,PDO::PARAM_INT);$q->execute();$pedidos=$q->fetchAll();$portal=portalEstudianteCabecera('Mis pedidos y pagos','pedidos','Consulta estados, dirección y documentos de tus compras.');?>
<div class="card"><div class="card-header"><h1 class="card-title">Mis pedidos</h1></div><div class="card-body"><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Pedido / fecha</th><th>Total</th><th>Estado</th><th>DTE</th><th>Documentos</th></tr></thead><tbody><?php foreach($pedidos as$p):?><tr><td><strong><?=atenea_e($p['numero'])?></strong><small class="d-block"><?=date('d/m/Y H:i',strtotime($p['created_at']))?></small></td><td>$<?=atenea_e($p['total'])?> <?=atenea_e(strtoupper($p['moneda']))?></td><td><span class="badge <?=claseEstadoPedido($p['estado'])?>"><?=atenea_e(estadoPedidoEstudiante($p['estado']))?></span></td><td><?php if($p['codigo_generacion']):?><small><?=atenea_e($p['numero_control'])?><br><?=atenea_e($p['estado_dte'])?></small><?php else:?><small class="text-muted">Pendiente</small><?php endif;?></td><td><a class="btn btn-sm btn-outline-secondary" href="<?=atenea_url('src/estudiantes/comprobante.php?pedido='.$p['id'])?>">Detalle</a><?php if($p['codigo_generacion']):?> <a class="btn btn-sm btn-outline-primary" href="<?=atenea_url('src/dte/documento.php?pedido='.$p['id'])?>">Ver PDF</a> <a class="btn btn-sm btn-outline-primary" href="<?=atenea_url('src/dte/documento.php?pedido='.$p['id'].'&tipo=json&descargar=1')?>">JSON</a><?php endif;?></td></tr><?php endforeach;?><?php if(!$pedidos):?><tr><td colspan="5" class="text-center py-5 text-muted">Aún no tienes pedidos.</td></tr><?php endif;?></tbody></table></div><?php $paginas=max(1,(int)ceil($total/$limite));if($paginas>1):?><nav><ul class="pagination justify-content-end"><?php for($i=1;$i<=$paginas;$i++):?><li class="page-item <?=$i===$pagina?'active':''?>"><a class="page-link" href="?pagina=<?=$i?>"><?=$i?></a></li><?php endfor;?></ul></nav><?php endif;?></div></div><?php portalEstudiantePie();
